import{n as c}from"./index-Doe0Amba.js";function y(){const r=document.getElementById("loginForm"),a=document.getElementById("error");r&&r.addEventListener("submit",async l=>{l.preventDefault(),a.textContent="";const d=document.getElementById("username").value,u=document.getElementById("password").value,t=r.querySelector("button"),m=t.innerText;t.disabled=!0,t.innerText="Autenticando...";try{const e=await fetch("http://127.0.0.1:4000/api/auth/login",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({username:d,password:u})});let o;const s=await e.text();try{o=JSON.parse(s)}catch{throw new Error(`Error en API ${e.url}: respuesta vacía o inválida (status ${e.status}). Texto: "${s}"`)}if(!e.ok)throw new Error(o.error||"Credenciales inválidas");const{token:p,user:i}=o;localStorage.setItem("authToken",p),localStorage.setItem("user",JSON.stringify(i));const n=(i.rol||"").toUpperCase();if(n==="ADMINISTRADOR")c("/admin");else if(n==="OPERARIO")c("/operario");else throw new Error("Rol de usuario desconocido: "+n)}catch(e){console.error("Login error:",e),a.textContent=e.message||"Error en la autenticación",t.disabled=!1,t.innerText=m}})}export{y as default};
